14	const BLOCK_OF_3_PRICE = 60;
15	
16	function basePremium(items: Item[]): number {
17	  if (items.length === 3) {
18	    return BLOCK_OF_3_PRICE;
19	  }
20	  return items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
21	}
22	
23	export function runScenario(steps: Step[]): unknown[] {
24	  return steps.map((step) => ({
25	    premium: PROCESSING_FEE + basePremium(step.items),
26	  }));
27	}
