const COMPONENT_TYPES = ["rune", "moonstone"];

function basePremium(items: Item[]): number {
  const countByType: Record<string, number> = {};
  for (const item of items) {
    countByType[item.type] = (countByType[item.type] ?? 0) + 1;
  }
  let total = 0;
  for (const type of Object.keys(countByType)) {
    const count = countByType[type];
    if (COMPONENT_TYPES.includes(type) && count === 3) {
      total += BLOCK_OF_3_PRICE;
    } else {
      total += count * BASE_PREMIUM_BY_TYPE[type];
    }
  }
  return total;
}
